   117|```rust
   118|/// Index all tool calls in messages, returning their locations and keys
   119|pub fn index_tool_calls(messages: &[MessageContent]) -> ToolCallIndex {
   120|    let mut by_location: HashMap<usize, HashMap<usize, String>> = HashMap::new();
   121|    let mut ordered_keys: Vec<String> = Vec::new();
   122|    let mut anonymous_call_index: usize = 0;
   123|
   124|    for (message_index, message) in messages.iter().enumerate() {
   125|        for (part_index, part) in message.content.iter().enumerate() {
   126|            if let ContentPart::ToolCall { tool_call_id, .. } = part {
   127|                let key = match tool_call_id {
   128|                    Some(id) => format!("id:{}", id),
   129|                    None => {
   130|                        let k = format!("anon:{}", anonymous_call_index);
   131|                        anonymous_call_index += 1;
   132|                        k
   133|                    }
   134|                };
   135|
   136|                let indexed_parts = by_location.entry(message_index).or_default();
   137|                indexed_parts.insert(part_index, key.clone());
   138|                ordered_keys.push(key);
   139|            }
   140|        }
   141|    }
   142|
   143|    ToolCallIndex {
   144|        by_location,
   145|        ordered_keys,
   146|    }
   147|}
   148|```
