   249|/// Check if a part is a tool call
   250|fn is_tool_call_part(part: &ContentPart) -> bool {
   251|    matches!(part, ContentPart::ToolCall { .. })
   252|}
   253|
   254|/// Check if a part is a tool result  
   255|fn is_tool_result_part(part: &ContentPart) -> bool {
   256|    matches!(part, ContentPart::ToolResult { .. })
   257|}
   258|
   259|/// Check if a tool call part is already compacted
   260|fn is_compacted_tool_call(part: &ContentPart, compacted_notice: &str) -> bool {
   261|    if let ContentPart::ToolCall { input, .. } = part {
   262|        if let Some(obj) = input.as_object() {
   263|            if let Some(compacted) = obj.get("compacted") {
   264|                if compacted.as_bool() == Some(true) {
   265|                    if let Some(msg) = obj.get("message") {
   266|                        return msg.as_str() == Some(compacted_notice);
   267|                    }
   268|                }
   269|            }
   270|        }
   271|    }
   272|    false
   273|}
   274|
   275|/// Check if a tool result part is already compacted
   276|fn is_compacted_tool_result(part: &ContentPart, compacted_notice: &str) -> bool {
   277|    if let ContentPart::ToolResult { output, .. } = part {
   278|        if let Some(obj) = output.as_object() {
   279|            if let Some(t) = obj.get("type") {
   280|                if t.as_str() == Some("text") {
   281|                    if let Some(v) = obj.get("value") {
   282|                        return v.as_str() == Some(compacted_notice);
   283|                    }
   284|                }
   285|            }
   286|        }
   287|    }
   288|    false
   289|}
