   294|```rust
   295|/// Find tool calls/results that are candidates for compaction
   296|pub fn find_pending_compaction_candidates(params: &FindPendingParams) -> PendingCompactionCandidates {
   297|    let mut pending_tool_call_keys: HashSet<String> = HashSet::new();
   298|    let mut pending_anonymous_tool_results: usize = 0;
   299|
   300|    for (message_index, message) in params.messages.iter().enumerate() {
   301|        let part_keys = params.tool_call_index.by_location.get(&message_index);
   302|
   303|        for (part_index, part) in message.content.iter().enumerate() {
   304|            if is_tool_call_part(part) {
   305|                if let Some(key) = part_keys.and_then(|k| k.get(&part_index)) {
   306|                    if !params.recent_tool_call_keys.contains(key)
   307|                        && !is_compacted_tool_call(part, &params.compacted_notice)
   308|                    {
   309|                        pending_tool_call_keys.insert(key.clone());
   310|                    }
   311|                }
   312|                continue;
   313|            }
   314|
   315|            if !is_tool_result_part(part) {
   316|                continue;
   317|            }
   318|
   319|            // Tool result handling
   320|            let tool_call_id = if let ContentPart::ToolResult { tool_call_id, .. } = part {
   321|                tool_call_id.clone()
   322|            } else {
   323|                None
   324|            };
   325|
   326|            let key = tool_call_id.map(|id| format!("id:{}", id));
   327|
   328|            if let Some(ref k) = key {
   329|                if !params.recent_tool_call_keys.contains(k)
   330|                    && !is_compacted_tool_result(part, &params.compacted_notice)
   331|                {
   332|                    pending_tool_call_keys.insert(k.clone());
   333|                }
   334|            } else if !is_compacted_tool_result(part, &params.compacted_notice) {
   335|                pending_anonymous_tool_results += 1;
   336|            }
   337|        }
   338|    }
   339|
   340|    PendingCompactionCandidates {
   341|        pending_tool_call_keys,
   342|        pending_anonymous_tool_results,
   343|    }
   344|}
   345|
   346|/// Parameters for find_pending_compaction_candidates
   347|pub struct FindPendingParams<'a> {
   348|    pub messages: &'a [MessageContent],
   349|    pub tool_call_index: &'a ToolCallIndex,
   350|    pub recent_tool_call_keys: &'a HashSet<String>,
   351|    pub compacted_notice: &'a str,
   352|}
   353|```
