{"content": "     1|//! Context Management Module
     2|//! 
     3|//! Provides data structures for managing conversation context, workspaces, and secrets.
     4|//! 
     5|//! ## Architecture
     6|//! 
     7|//! - `Conversation`: A single conversation/session with messages
     8|//! - `Workspace`: A workspace containing multiple conversations  
     9|//! - `Secrets`: Secure key-value storage for sensitive data
    10|//! - `ContextStore`: Trait for abstracting storage mechanisms
    11|
    12|use chrono::{DateTime, Utc};
    13|use serde::{Deserialize, Serialize};
    14|use std::collections::HashMap;
    15|use uuid::Uuid;
    16|
    17|/// Workspace metadata file stored at .omg/state/workspaces.json
    18|pub const WORKSPACES_INDEX_FILE: &str = "workspaces.json";
    19|
    20|/// Workspace data stored at .omg/state/workspaces/{id}.json
    21|pub fn workspace_file_path(id: Uuid) -> String {
    22|    format!("workspaces/{}.json", id)
    23|}
    24|
    25|/// Secrets file stored at .omg/state/secrets/{id}.json
    26|pub fn secrets_file_path(id: Uuid) -> String {
    27|    format!("secrets/{}.json", id)
    28|}
    29|
    30|/// A single message in a conversation
    31|#[derive(Debug, Clone, Serialize, Deserialize, PartialEq)]
    32|pub struct Message {
    33|    pub role: MessageRole,
    34|    pub content: String,
    35|    pub timestamp: DateTime<Utc>,
    36|}
    37|
    38|/// Role of a message sender
    39|#[derive(Debug, Clone, Serialize, Deserialize, PartialEq, Eq, Hash)]
    40|pub enum MessageRole {
    41|    #[serde(rename = "user")]
    42|    User,
    43|    #[serde(rename = "assistant")]
    44|    Assistant,
    45|    #[serde(rename = "system")]
    46|    System,
    47|}
    48|
    49|/// A conversation represents a single session with multiple messages
    50|#[derive(Debug, Clone, Serialize, Deserialize, PartialEq)]
    51|pub struct Conversation {
    52|    pub id: Uuid,
    53|    pub workspace_id: Uuid,
    54|    pub messages: Vec<Message>,
    55|    pub metadata: HashMap<String, serde_json::Value>,
    56|}
    57|
    58|impl Conversation {
    59|    /// Create a new conversation with a given workspace ID
    60|    pub fn new(workspace_id: Uuid) -> Self {
    61|        Self {
    62|            id: Uuid::new_v4(),
    63|            workspace_id,
    64|            messages: Vec::new(),
    65|            metadata: HashMap::new(),
    66|        }
    67|    }
    68|
    69|    /// Add a message to the conversation
    70|    pub fn add_message(&mut self, role: MessageRole, content: String) {
    71|        self.messages.push(Message {
    72|            role,
    73|            content,
    74|            timestamp: Utc::now(),
    75|        });
    76|    }
    77|}
    78|
    79|/// A workspace contains multiple conversations
    80|#[derive(Debug, Clone, Serialize, Deserialize, PartialEq)]
    81|pub struct Workspace {
    82|    pub id: Uuid,
    83|    pub name: String,
    84|    pub conversations: HashMap<Uuid, Conversation>,
    85|    pub created_at: DateTime<Utc>,
    86|    pub updated_at: DateTime<Utc>,
    87|}
    88|
    89|impl Workspace {
    90|    /// Create a new workspace
    91|    pub fn new(name: String) -> Self {
    92|        let now = Utc::now();
    93|        Self {
    94|            id: Uuid::new_v4(),
    95|            name,
    96|            conversations: HashMap::new(),
    97|            created_at: now,
    98|            updated_at: now,
    99|        }
   100|    }
   101|
   102|    /// Add a conversation to the workspace
   103|    pub fn add_conversation(&mut self, conversation: Conversation) {
   104|        self.conversations.insert(conversation.id, conversation);
   105|        self.updated_at = Utc::now();
   106|    }
   107|}
   108|
   109|/// Secrets storage for sensitive data
   110|#[derive(Debug, Clone, Serialize, Deserialize, PartialEq)]
   111|pub struct Secrets {
   112|    pub entries: HashMap<String, String>,
   113|    pub encrypted: bool,
   114|}
   115|
   116|impl Secrets {
   117|    /// Create a new empty secrets store
   118|    pub fn new() -> Self {
   119|        Self {
   120|            entries: HashMap::new(),
   121|            encrypted: false,
   122|        }
   123|    }
   124|
   125|    /// Set a secret value
   126|    pub fn set(&mut self, key: impl Into<String>, value: impl Into<String>) {
   127|        self.entries.insert(key.into(), value.into());
   128|    }
   129|
   130|    /// Get a secret value
   131|    pub fn get(&self, key: &str) -> Option<&String> {
   132|        self.entries.get(key)
   133|    }
   134|
   135|    /// Remove a secret
   136|    pub fn remove(&mut self, key: &str) -> Option<String> {
   137|        self.entries.remove(key)
   138|    }
   139|}
   140|
   141|impl Default for Secrets {
   142|    fn default() -> Self {
   143|        Self::new()
   144|    }
   145|}
   146|
   147|/// Context store trait for abstracting storage mechanisms
   148|#[async_trait::async_trait]
